Here's a minimal API endpoint that handles multipart form uploads with multiple images and a description:

```csharp
using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(o =>
    o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Ensure it's a multipart form request
    if (!request.HasFormContentType)
        return Results.BadRequest("Expected a multipart/form-data request.");

    var form = await request.ReadFormAsync();
    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images");   // matches <input name="images" />

    if (files.Count == 0)
        return Results.BadRequest("No image files provided.");

    var saved = new List<string>();

    foreach (var file in files)
    {
        // Basic content-type guard
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        var dest = Path.Combine(Path.GetTempPath(), $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}");
        await using var stream = File.Create(dest);
        await file.CopyToAsync(stream);
        saved.Add(dest);
    }

    return Results.Ok(new
    {
        Description = description,
        FileCount = saved.Count,
        Paths = saved
    });
})
.DisableAntiforgery()                       // needed when there's no AF token
.Accepts<IFormFile>("multipart/form-data");

app.Run();
```

**Key points:**

- **`MaxRequestBodySize`** — Kestrel defaults to ~30 MB; set it to 50 MB explicitly.
- **`ReadFormAsync`** — gives you both the text fields and the uploaded files.
- **`form.Files.GetFiles("images")`** — pulls all files submitted under the `images` field name.
- **`.DisableAntiforgery()`** — required for API-style endpoints without an antiforgery token.

**Test with `curl`:**

```bash
curl -X POST http://localhost:5000/upload \
  -F "description=Vacation photos" \
  -F "images=@photo1.jpg" \
  -F "images=@photo2.png"
```

For production, swap `Path.GetTempPath()` for a real storage destination (Azure Blob, S3, etc.) and add size-per-file validation.
